import { TrackerEntry } from '@/hooks/useTracker';

interface Props {
  entries: Record<string, TrackerEntry>;
}

export default function TrackerStats({ entries }: Props) {
  const all = Object.values(entries);
  const total = all.length;
  const completed = all.filter(e => e.status === 'completed').length;
  const inProgress = all.filter(e => e.status === 'in_progress').length;
  const pending = all.filter(e => e.status === 'pending').length;

  const cards = [
    {
      label: 'Total elementos',
      value: total,
      icon: 'ri-stack-line',
      accent: '#2563EB',
      bg: 'rgba(37,99,235,0.1)',
    },
    {
      label: 'Completados',
      value: completed,
      icon: 'ri-checkbox-circle-line',
      accent: '#22c55e',
      bg: 'rgba(34,197,94,0.1)',
    },
    {
      label: 'En progreso',
      value: inProgress,
      icon: 'ri-loader-4-line',
      accent: '#f97316',
      bg: 'rgba(249,115,22,0.1)',
    },
    {
      label: 'Pendientes',
      value: pending,
      icon: 'ri-bookmark-line',
      accent: '#94a3b8',
      bg: 'rgba(148,163,184,0.1)',
    },
  ];

  return (
    <div className="mb-6 grid grid-cols-2 gap-4 lg:grid-cols-4">
      {cards.map(card => (
        <div
          key={card.label}
          className="flex items-center gap-4 rounded-2xl border border-[var(--border)] bg-[var(--surface)] p-5 transition-colors hover:border-[var(--border-strong)]"
        >
          <div
            className="flex h-11 w-11 flex-shrink-0 items-center justify-center rounded-xl"
            style={{ background: card.bg }}
          >
            <i className={`${card.icon} text-lg`} style={{ color: card.accent }} />
          </div>
          <div>
            <p
              className="text-2xl font-black leading-none text-[var(--text-primary)]"
              style={{ fontFamily: "'Space Grotesk', sans-serif" }}
            >
              {card.value}
            </p>
            <p className="mt-1 text-xs leading-tight text-[var(--text-secondary)]">{card.label}</p>
          </div>
        </div>
      ))}
    </div>
  );
}
