import { Link } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { TrackerEntry } from '@/hooks/useTracker';

interface Props {
  entries: Record<string, TrackerEntry>;
}

export default function TrackerHero({ entries }: Props) {
  const { profile, user } = useAuth();
  const total = Object.values(entries).length;
  const displayName = profile?.display_name ?? profile?.username ?? user?.email?.split('@')[0] ?? 'Usuario';
  const initials = (profile as { initials?: string } | null)?.initials ?? displayName.slice(0, 2).toUpperCase();

  return (
    <div className="relative overflow-hidden rounded-2xl border border-[var(--border)] bg-[var(--surface)] mb-6">
      {/* Ambient background layers */}
      <div className="pointer-events-none absolute inset-0 bg-gradient-to-br from-blue-600/6 via-transparent to-orange-500/5" />
      <div className="pointer-events-none absolute -right-24 -top-24 h-80 w-80 rounded-full bg-blue-500/6 blur-3xl" />
      <div className="pointer-events-none absolute -left-12 bottom-0 h-40 w-40 rounded-full bg-orange-500/5 blur-2xl" />

      <div className="relative flex flex-col gap-6 p-6 md:flex-row md:items-center md:gap-8 md:p-8">
        {/* Avatar + info */}
        <div className="flex items-center gap-5">
          <div className="relative flex-shrink-0">
            {profile?.avatar_url ? (
              <img
                src={profile.avatar_url}
                alt={displayName}
                className="h-16 w-16 rounded-2xl object-cover object-top ring-2 ring-blue-500/30"
              />
            ) : (
              <div className="flex h-16 w-16 items-center justify-center rounded-2xl bg-gradient-to-br from-blue-500 to-blue-700 text-xl font-black text-white ring-2 ring-blue-500/30">
                {initials}
              </div>
            )}
            {/* Online dot */}
            <span className="absolute -bottom-1 -right-1 h-4 w-4 rounded-full border-2 border-[var(--surface)] bg-emerald-500" />
          </div>

          <div>
            <p className="mb-0.5 text-xs font-semibold uppercase tracking-widest text-[var(--text-secondary)]">
              Tu colección personal
            </p>
            <h1
              className="text-2xl font-black text-[var(--text-primary)] md:text-3xl"
              style={{ fontFamily: "'Space Grotesk', sans-serif" }}
            >
              {displayName}
            </h1>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              Gestiona todo lo que has visto, leído, jugado o escuchado.
              {total > 0 && (
                <span className="ml-2 font-semibold text-[var(--brand-accent)]">
                  {total} {total === 1 ? 'elemento' : 'elementos'}
                </span>
              )}
            </p>
          </div>
        </div>

        {/* CTAs */}
        <div className="flex flex-shrink-0 items-center gap-3 md:ml-auto">
          <Link
            to="/catalog"
            className="inline-flex items-center gap-2 rounded-xl bg-[var(--brand-accent)] px-5 py-2.5 text-sm font-semibold text-white transition-colors hover:bg-[var(--brand-accent-hover)] cursor-pointer"
          >
            <i className="ri-add-line" />
            Añadir elemento
          </Link>
          <button className="inline-flex items-center gap-2 rounded-xl border border-[var(--border)] bg-[var(--surface-raised)] px-5 py-2.5 text-sm font-semibold text-[var(--text-secondary)] transition-colors hover:border-[var(--border-strong)] hover:text-[var(--text-primary)] cursor-pointer">
            <i className="ri-upload-2-line" />
            Importar
          </button>
        </div>
      </div>
    </div>
  );
}
